export interface NotificationEvent {
  type: 'email' | 'sms' | 'webhook';
  recipient: string;
  subject: string;
  body: string;
}

/**
 * SMS channel handler — subscribes to the notification event bus
 * and stores SMS notifications.
 */
export class SmsChannelHandler {
  private logger = new Logger('SmsChannelHandler');
  private sent: Notification[] = [];

  constructor(private notificationBus: NotificationEventBus<NotificationEventMap>) {
    this.notificationBus.subscribe('notification:send', (event) => {
      if (event.type === 'sms') {
        this.handleSms(event);
      }
    });
  }

  private handleSms(event: NotificationEvent): void {
    const notification: Notification = {
      id: generateNotificationId(),
      type: 'sms',
      recipient: event.recipient,
      subject: event.subject,
      body: event.body,
      sentAt: new Date(),
    };
    this.sent.push(notification);
    this.logger.info(`SMS sent: ${notification.id} to ${event.recipient}`);
  }

  getSentMessages(): Notification[] {
    return [...this.sent];
  }

  getSentCount(): number {
    return this.sent.length;
  }

  clearSent(): void {
    this.sent = [];
  }
}

